function csv(){
  if(state.coreIncomplete)return msg('التصدير النهائي متوقف حتى تكتمل مصادر البيانات.',true);
  const rows=currentRows(),month=$('salaryMonth')?.value||'',X=window.XLSX;
  if(!X)return msg('تعذر تحميل مكتبة Excel.',true);
  const headers=['رقم','أيدي الموظف','الشهر','اسم الموظف في الإقامة','اسم الموظف الحركي','رقم الإقامة','مكان العمل','الوظيفة','بداية الخدمة','نهاية الخدمة','أيام العمل','أيام الغياب','الأيام المستحقة','قيمة الرواتب الأساسية','البدلات','الإجمالي','إجمالي الراتب على أيام الفترة','العمولات','الخصومات','جبر الكسور','خصم السلف','الصافي','ملاحظات'];
  const aoa=[['كشف الرواتب'],[`الشهر: ${month} - شركة تصنيف لإدارة المرافق`],headers];
  rows.forEach((r,i)=>aoa.push([i+1,r.employee_code,r.month,r.residency_name,r.worker_name,r.iqama_number,r.work_location,r.job_title,r.service_start,r.service_end,r.work_days,r.absent_days,r.due_days,r.base_salary,r.allowances,r.gross_salary,r.period_salary,r.commissions,r.deductions,r.rounding,r.advances,r.net_salary,r.notes||r.issues.join('، ')]));
  const sums=k=>rows.reduce((s,r)=>s+N(r[k]),0);
  aoa.push(['الإجمالي','','','','','','','','','','','','',sums('base_salary'),sums('allowances'),sums('gross_salary'),sums('period_salary'),sums('commissions'),sums('deductions'),sums('rounding'),sums('advances'),sums('net_salary'),'']);
  const ws=X.utils.aoa_to_sheet(aoa),wb=X.utils.book_new();ws['!rtl']=true;
  ws['!merges']=[X.utils.decode_range('A1:W1'),X.utils.decode_range('A2:W2')];
  ws['!cols']=[7,13,12,24,18,16,20,13,13,13,11,11,12,15,12,13,19,12,12,11,12,14,30].map(w=>({wch:w}));
  X.utils.book_append_sheet(wb,ws,'مع العمولة');X.writeFile(wb,`كشف_الرواتب_${month}.xlsx`,{compression:true,cellStyles:true});
}
